\relinput{Figures/Q09-BagBalls.tex}

\vgap

A bag contains 5 white balls and 3 black balls.

\begin{parts}
\item \,

\begin{subparts}
\item Marwan picks a ball from the bag at random and then replaces it.

\vgap

Find the probability that the ball is white.

\AnswerLine[][]
\Marks{1}

\item Naomi picks a ball from the bag at random and then replaces it.

She repeats this 120 times.

\vgap

Find the number of times the ball is expected to be white.

\AnswerLine[][]
\Marks{1}

\end{subparts}

\item Oscar picks a ball from the bag at random.

He replaces it and then picks a second ball from the bag at random.

\begin{subparts}
\item Find the probability that the balls are the same colour.

\AnswerLine[][]
\Marks{3}

\item Find the probability that the balls are \textbf{not} the same colour.

\AnswerLine[][]
\Marks{1}

\end{subparts}

\item Priya picks 3 of the 8 balls from the bag at random without replacement.

\vgap

Find the probability that she picks two white balls and one black ball.

\AnswerLine[][]
\Marks{3}

\end{parts}

